import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { adminDashboardDesign } from "../../design/adminDashboardDesign";

const AdminDashboard = () => {
  const adminInfo = JSON.parse(localStorage.getItem("adminInfo"));
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div className={adminDashboardDesign.layout.wrapper}>
      
      {/* 🔥 Sidebar */}
      <AnimatePresence>
        {isOpen && (
          <>
            {/* Overlay (Mobile only) */}
            <motion.div
              {...adminDashboardDesign.animation.overlay}
              className={`fixed inset-0 z-40 md:hidden ${adminDashboardDesign.colors.overlay}`}
              onClick={() => setIsOpen(false)}
            />

            {/* Sidebar */}
            <motion.aside
              {...adminDashboardDesign.animation.sidebar}
              className={`${adminDashboardDesign.colors.sidebar} ${adminDashboardDesign.layout.sidebar}`}
            >
              <h2 className="text-2xl font-bold text-indigo-400">
                Admin Panel
              </h2>

              <nav className="space-y-3">
                <div className={`${adminDashboardDesign.layout.navItem} ${adminDashboardDesign.colors.hover}`}>
                  Dashboard
                </div>
                <div className={`${adminDashboardDesign.layout.navItem} ${adminDashboardDesign.colors.hover}`}>
                  Products
                </div>
                <div className={`${adminDashboardDesign.layout.navItem} ${adminDashboardDesign.colors.hover}`}>
                  Orders
                </div>
                <div className={`${adminDashboardDesign.layout.navItem} ${adminDashboardDesign.colors.hover}`}>
                  Users
                </div>
              </nav>
            </motion.aside>
          </>
        )}
      </AnimatePresence>

      {/* 🔥 Right Side */}
      <div
        className={`${adminDashboardDesign.layout.contentWrapper} md:ml-64`}
      >
        {/* Navbar */}
        <div className={`${adminDashboardDesign.colors.navbar} ${adminDashboardDesign.layout.navbar}`}>
          
          {/* Toggle Button (Mobile only) */}
          <button
            onClick={() => setIsOpen(true)}
            className={`md:hidden ${adminDashboardDesign.colors.toggleBtn}`}
          >
            ☰
          </button>

          <h1 className="font-semibold text-lg hidden md:block">
            Dashboard
          </h1>

          <div className="flex items-center gap-4">
            <span className="text-sm text-gray-600">
              {adminInfo?.name}
            </span>
            <div className="w-8 h-8 bg-indigo-500 rounded-full"></div>
          </div>
        </div>

        {/* Main Content */}
        <div className={adminDashboardDesign.layout.content}>
          <h2 className="text-2xl font-bold mb-4">
            Welcome Back 👋
          </h2>

          <p className="text-gray-600">
            This is your admin dashboard overview.
          </p>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
